function solve(nums, queries) {
    // Precompute popcount-depth for numbers up to 1e15
    const memo = new Map();

    function popcount(x) {
        let count = 0;
        while (x > 0) {
            count += x & 1;
            x >>>= 1;
        }
        return count;
    }

    function getDepth(x) {
        if (x === 1) return 0;
        if (memo.has(x)) return memo.get(x);
        const next = popcount(x);
        const depth = 1 + getDepth(next);
        memo.set(x, depth);
        return depth;
    }

    // Initialize depths array
    const depths = new Array(nums.length);
    for (let i = 0; i < nums.length; i++) {
        depths[i] = getDepth(nums[i]);
    }

    const answer = [];

    for (const query of queries) {
        if (query[0] === 1) {
            const [_, l, r, k] = query;
            let count = 0;
            for (let j = l; j <= r; j++) {
                if (depths[j] === k) {
                    count++;
                }
            }
            answer.push(count);
        } else if (query[0] === 2) {
            const [_, idx, val] = query;
            nums[idx] = val;
            depths[idx] = getDepth(val);
        }
    }

    return answer;
}

