use std::collections::HashMap;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let mut memo: HashMap<i64, i64> = HashMap::new();

    fn popcount(x: i64) -> i64 {
        let mut count = 0;
        let mut n = x;
        while n > 0 {
            count += n & 1;
            n >>= 1;
        }
        count
    }

    fn get_depth(x: i64, memo: &mut HashMap<i64, i64>) -> i64 {
        if x == 1 {
            return 0;
        }
        if let Some(&depth) = memo.get(&x) {
            return depth;
        }
        let next = popcount(x);
        let depth = 1 + get_depth(next, memo);
        memo.insert(x, depth);
        depth
    }

    let mut depths: Vec<i64> = nums.iter().map(|&x| get_depth(x, &mut memo)).collect();
    let mut answer = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let l = query[1] as usize;
            let r = query[2] as usize;
            let k = query[3];
            let count = depths[l..=r].iter().filter(|&&d| d == k).count() as i64;
            answer.push(count);
        } else if query[0] == 2 {
            let idx = query[1] as usize;
            let val = query[2];
            depths[idx] = get_depth(val, &mut memo);
        }
    }

    answer
}
